changeSet.sql:
update file_document
set file_name = REPLACE(file_name, 'Underlying Agreement', 'CCA2 Underlying Agreement')
where file_name like '%[proposed]%';

changeSet.rollback:
	update file_document
    set file_name = REPLACE(file_name, 'CCA2 Underlying Agreement', 'Underlying Agreement')
    where file_name like '%[proposed]%';

changeSet.sql:
update file_document
set file_name = REPLACE(file_name, 'Underlying Agreement', 'CCA2 Underlying Agreement')
where file_name like '%Underlying Agreement v%' and file_name not like '%[proposed]%';

changeSet.rollback:
	update file_document
    set file_name = REPLACE(file_name, 'CCA2 Underlying Agreement', 'Underlying Agreement')
    where file_name like '%Underlying Agreement v%' and file_name not like '%[proposed]%';
